601.answer:
Refactoring duplicate conditional discount logic in JavaScript means extracting repeated if/else chains into a single lookup table or helper function.

Before (duplicated logic):
```javascript
function getPrintPrice(user, book) {
  let price = book.printPrice;
  if (user.type === 'member') price *= 0.9;
  else if (user.type === 'student') price *= 0.8;
  else if (user.type === 'senior') price *= 0.85;
  if (book.category === 'textbook') price *= 0.95;
  else if (book.category === 'fiction') price *= 1.0;
  else if (book.category === 'rare') price *= 1.2;
  return price;
}

function getEbookPrice(user, book) {
  let price = book.ebookPrice;
  if (user.type === 'member') price *= 0.9;
  else if (user.type === 'student') price *= 0.8;
  else if (user.type === 'senior') price *= 0.85;
  if (book.category === 'textbook') price *= 0.95;
  else if (book.category === 'fiction') price *= 1.0;
  else if (book.category === 'rare') price *= 1.2;
  return price;
}
```

After (shared helper):
```javascript
const USER_DISCOUNTS = { member: 0.9, student: 0.8, senior: 0.85 };
const BOOK_MULTIPLIERS = { textbook: 0.95, fiction: 1.0, rare: 1.2 };

function applyDiscounts(basePrice, user, book) {
  const userMultiplier = USER_DISCOUNTS[user.type] ?? 1.0;
  const bookMultiplier = BOOK_MULTIPLIERS[book.category] ?? 1.0;
  return basePrice * userMultiplier * bookMultiplier;
}

function getPrintPrice(user, book) {
  return applyDiscounts(book.printPrice, user, book);
}

function getEbookPrice(user, book) {
  return applyDiscounts(book.ebookPrice, user, book);
}
```

Key changes: extracted the repeated conditional chains into lookup objects (`USER_DISCOUNTS`, `BOOK_MULTIPLIERS`) and a shared `applyDiscounts` helper. Both public functions now delegate to it, eliminating duplication while preserving identical behavior.

602.answer:
Reducing deeply nested conditionals in Python uses early-return (guard clauses) to flatten the structure and make each condition self-contained.

Before (deeply nested):
```python
def process_order(order):
    if order is not None:
        if order.get('status') == 'active':
            if order.get('items'):
                total = 0
                for item in order['items']:
                    if item.get('available'):
                        if item.get('price') is not None:
                            total += item['price'] * item.get('qty', 1)
                return total
            else:
                return 0
        else:
            return None
    else:
        return None
```

After (guard clauses, flat nesting):
```python
def process_order(order):
    if order is None:
        return None
    if order.get('status') != 'active':
        return None
    if not order.get('items'):
        return 0

    total = 0
    for item in order['items']:
        if not item.get('available'):
            continue
        if item.get('price') is None:
            continue
        total += item['price'] * item.get('qty', 1)
    return total
```

Key changes: inverted each condition to a guard/early return at the top of the function, eliminating nesting. The inner loop uses `continue` to skip invalid items instead of nesting further. Output is identical.

