  let subtotal = 0;
  for (const item of items) {
    const lineTotal = item.price * item.qty;
    const discountAmount = item.discount ? lineTotal * item.discount : 0;
    subtotal += lineTotal - discountAmount;
  }
  const taxAmount = subtotal * taxRate;
  return subtotal + taxAmount;
}
```

Key changes: `s` -> `subtotal`, `t` -> `lineTotal`, `d` -> `discountAmount`, `tx` -> `taxAmount`. No logic changed; the function produces the same result.

