// Refactored: extract accumulate helper; keep both exported functions
function accumulate(items, valueKey, labelKey) {
  return items.reduce((acc, item) => {
    const label = item[labelKey];
    acc[label] = (acc[label] || 0) + item[valueKey];
    return acc;
  }, {});
}

export function totalByCategory(items) { return accumulate(items, 'amount', 'category'); }
export function totalByRegion(items)   { return accumulate(items, 'amount', 'region'); }

