// Refactored: separate format from select; compose in listAffordable
function formatProduct(p) {
  return `${p.name} - $${p.price.toFixed(2)}`;
}

function selectAffordable(products, budget) {
  return products.filter(p => p.price <= budget);
}

function listAffordable(products, budget) {
  return selectAffordable(products, budget).map(formatProduct);
}

